 69→func renderCheckpointBlock(s checkpoint.CheckpointSummary, width int) string {
 70→	sep := dimStyle.Render("  ·  ")
 71→
 72→	title := s.CommitMessage
 73→	if title == "" {
 74→		title = cleanPromptExcerpt(s.Prompt)
 75→	}
 76→	if title == "" {
 77→		title = s.Context
 78→	}
 79→	if title == "" {
 80→		title = s.Branch
 81→	}
 82→	if idx := strings.IndexByte(title, '\n'); idx >= 0 {
 83→		title = title[:idx]
 84→	}
 85→	title = strings.TrimSpace(title)
 86→	if len(title) > width {
 87→		title = title[:width-1] + "…"
 88→	}
 89→	line1 := lipgloss.NewStyle().Bold(true).Render(title)
 90→
 91→	subtitle := ""
 92→	if s.CommitMessage != "" {
 93→		excerpt := cleanPromptExcerpt(s.Prompt)
 94→		if excerpt != "" && excerpt != title {
 95→			if len(excerpt) > width {
 96→				excerpt = excerpt[:width-1] + "…"
 97→			}
 98→			subtitle = dimStyle.Render(excerpt)
 99→		}
100→	}
101→
102→	var leftParts []string
103→	leftParts = append(leftParts, hashStyle.Render(truncateHash(s.ID)))
104→	timeStr := formatTimeAgo(s.CreatedAt)
105→	if timeStr != "" {
106→		leftParts = append(leftParts, dimStyle.Render(timeStr))
107→	}
108→	attribution := formatAttribution(s)
109→	if attribution != "" {
110→		leftParts = append(leftParts, agentBadgeStyle.Render(attribution))
111→	}
112→	leftSide := strings.Join(leftParts, sep)
113→
114→	colDiff := lipgloss.NewStyle().Width(14).Align(lipgloss.Right)
115→	colFiles := lipgloss.NewStyle().Width(10).Align(lipgloss.Right)
116→	colSessions := lipgloss.NewStyle().Width(12).Align(lipgloss.Right)
117→	colTokens := lipgloss.NewStyle().Width(14).Align(lipgloss.Right)
118→
119→	var rightCols []string
120→	if s.Additions > 0 || s.Deletions > 0 {
121→		diffStr := addStyle.Render(fmt.Sprintf("+%d", s.Additions)) + " / " +
122→			delStyle.Render(fmt.Sprintf("-%d", s.Deletions))
123→		rightCols = append(rightCols, colDiff.Render(diffStr))
124→	} else {
125→		rightCols = append(rightCols, colDiff.Render(""))
126→	}
127→	if s.FileCount > 0 {
128→		rightCols = append(rightCols, colFiles.Render(dimStyle.Render(fmt.Sprintf("%d files", s.FileCount))))
129→	} else {
130→		rightCols = append(rightCols, colFiles.Render(""))
131→	}
132→	if s.SessionCount > 0 {
133→		label := "session"
134→		if s.SessionCount > 1 {
135→			label = "sessions"
136→		}
137→		rightCols = append(rightCols, colSessions.Render(dimStyle.Render(fmt.Sprintf("%d %s", s.SessionCount, label))))
138→	} else {
139→		rightCols = append(rightCols, colSessions.Render(""))
140→	}
141→	if s.TotalTokens > 0 {
142→		rightCols = append(rightCols, colTokens.Render(dimStyle.Render(formatTokensShort(s.TotalTokens))))
143→	} else {
144→		rightCols = append(rightCols, colTokens.Render(""))
145→	}
146→	rightSide := strings.Join(rightCols, dimStyle.Render(" · "))
147→
148→	metaLine := leftSide
149→	if rightSide != "" {
150→		padding := width - lipgloss.Width(leftSide) - lipgloss.Width(rightSide)
151→		if padding < 2 {
152→			padding = 2
153→		}
154→		metaLine = leftSide + strings.Repeat(" ", padding) + rightSide
155→	}
156→
157→	if subtitle != "" {
158→		return line1 + "\n" + subtitle + "\n" + metaLine
159→	}
160→	return line1 + "\n" + metaLine
161→}
